// 扩展的高校数据结构
type ExtendedUniversity struct {
	ID           int    `json:"id"`
	Code         string `json:"code"`
	Name         string `json:"name"`
	Province     string `json:"province"`
	City         string `json:"city"`
	Type         string `json:"type"`
	Level        string `json:"level"`
	NationalRank int    `json:"national_rank"`
	IsActive     bool   `json:"is_active"`
	Website      string `json:"website"`
	Description  string `json:"description"`
	Founded      int    `json:"founded"`
	Students     int    `json:"students"`
}

// 扩展的专业数据结构
type ExtendedMajor struct {
	ID           int    `json:"id"`
	UniversityID int    `json:"university_id"`
	Code         string `json:"code"`
	Name         string `json:"name"`
	Category     string `json:"category"`
	IsActive     bool   `json:"is_active"`
	Duration     int    `json:"duration"`
	Degree       string `json:"degree"`
	Description  string `json:"description"`
}

// 录取数据结构
type ExtendedAdmissionData struct {
	ID           int    `json:"id"`
	UniversityID int    `json:"university_id"`
	MajorID      int    `json:"major_id"`
	Year         int    `json:"year"`
	Province     string `json:"province"`
	MinScore     int    `json:"min_score"`
	AvgScore     int    `json:"avg_score"`
	MaxScore     int    `json:"max_score"`
	MinRank      int    `json:"min_rank"`
	AvgRank      int    `json:"avg_rank"`
	MaxRank      int    `json:"max_rank"`
}

// 统一响应格式
type ExtendedResponse struct {
	Success bool        `json:"success"`
	Data    interface{} `json:"data"`
	Message string      `json:"message"`
	Total   int         `json:"total,omitempty"`
}

// 智能推荐相关数据结构
type RecommendationRequest struct {
	Score          int      `json:"score"`           // 高考分数
	Province       string   `json:"province"`        // 所在省份
	SubjectType    string   `json:"subject_type"`    // 文理科类型
	Year           int      `json:"year"`            // 高考年份
	Rank           int      `json:"rank"`            // 位次排名
	PreferredArea  string   `json:"preferred_area"`  // 意向地区
	PreferredMajor string   `json:"preferred_major"` // 专业类别
	UniversityType []string `json:"university_type"` // 院校类型
	RiskLevel      string   `json:"risk_level"`      // 风险承受度
	SpecialReq     string   `json:"special_req"`     // 特殊要求
}

type RecommendationResult struct {
	SchemeType   string                  `json:"scheme_type"`  // 方案类型：冲刺、稳妥、保底
	Universities []RecommendedUniversity `json:"universities"` // 推荐高校
	TotalCount   int                     `json:"total_count"`  // 推荐总数
	RiskWarning  string                  `json:"risk_warning"` // 风险提醒
	Suggestions  []string                `json:"suggestions"`  // 填报建议
}

type RecommendedUniversity struct {
	University      ExtendedUniversity `json:"university"`       // 高校信息
	Major           ExtendedMajor      `json:"major"`            // 专业信息
	AdmissionProb   float64            `json:"admission_prob"`   // 录取概率
	ScoreDifference int                `json:"score_difference"` // 分数差距
	RankDifference  int                `json:"rank_difference"`  // 排名差距
	RecommendReason string             `json:"recommend_reason"` // 推荐理由
	RiskLevel       string             `json:"risk_level"`       // 风险等级
}

// 增强版推荐算法相关类型定义
type EnhancedRecommendationEngine struct {
	historicalData  map[string][]HistoricalAdmission // 历史录取数据
	userPreferences map[string]float64               // 用户偏好权重
	marketTrends    map[string]float64               // 就业市场趋势
}

// 历史录取数据结构
type HistoricalAdmission struct {
	Year             int
	MinScore         int
	MaxScore         int
	AvgScore         int
	MinRank          int
	MaxRank          int
	AvgRank          int
	AdmissionCount   int
	ApplicationCount int
}

// 增强版推荐请求
type EnhancedRecommendationRequest struct {
	RecommendationRequest     // 继承原有请求
	PersonalityType           string   // 性格类型
	CareerGoals               []string // 职业目标
	FamilyIncome              int      // 家庭收入
	GeographicFlexibility     float64  // 地域灵活度 0-1
	MajorFlexibility          float64  // 专业灵活度 0-1
	RiskTolerance             float64  // 风险承受度 0-1
}

// 增强版推荐结果
type EnhancedRecommendationResult struct {
	RecommendationResult     // 继承原有结果
	ConfidenceScore          float64                 // 推荐置信度
	PersonalizationScore     float64                 // 个性化匹配度
	MarketOutlook            string                  // 就业市场前景
	AlternativeOptions       []RecommendedUniversity // 备选方案
}

// 全局数据存储
var (
	extendedUniversities  []ExtendedUniversity
	extendedMajors        []ExtendedMajor
	extendedAdmissionData []ExtendedAdmissionData
)

