// 增强版推荐引擎实例
var enhancedEngine *EnhancedRecommendationEngine

// 初始化增强推荐引擎
func initEnhancedRecommendationEngine() {
	if enhancedEngine == nil {
		enhancedEngine = NewEnhancedRecommendationEngine()
	}
}

// 智能推荐算法实现 - 增强版
func generateRecommendations(req RecommendationRequest) []RecommendationResult {
	// 确保增强引擎已初始化
	initEnhancedRecommendationEngine()

	// 转换为增强版请求
	enhancedReq := EnhancedRecommendationRequest{
		RecommendationRequest: req,
		PersonalityType: "理性型", // 默认性格类型
		CareerGoals: []string{}, // 默认空职业目标
		FamilyIncome: 80000, // 默认家庭收入
		GeographicFlexibility: 0.5, // 默认地域灵活度
		MajorFlexibility: 0.5, // 默认专业灵活度
		RiskTolerance: 0.5, // 默认风险承受度
	}

	// 根据原有风险等级调整新的风险承受度
	switch req.RiskLevel {
	case "保守型（冲1保5稳4）":
		enhancedReq.RiskTolerance = 0.2
	case "稳健型（冲2保3稳5）":
		enhancedReq.RiskTolerance = 0.5
	case "激进型（冲4保2稳4）":
		enhancedReq.RiskTolerance = 0.8
	default:
		enhancedReq.RiskTolerance = 0.5
	}

	// 生成增强版推荐
	enhancedResults := enhancedEngine.GenerateEnhancedRecommendations(enhancedReq)

	// 转换为原有格式
	results := []RecommendationResult{}
	for _, enhancedResult := range enhancedResults {
		result := RecommendationResult{
			SchemeType: enhancedResult.SchemeType,
			Universities: enhancedResult.Universities,
			TotalCount: enhancedResult.TotalCount,
			RiskWarning: enhancedResult.RiskWarning,
			Suggestions: enhancedResult.Suggestions,
		}
		results = append(results, result)
	}

	return results
}

// 生成特定类型的推荐方案
func generateScheme(schemeType string, req RecommendationRequest, count int) RecommendationResult {
	recommendations := []RecommendedUniversity{}

	// 根据方案类型调整分数范围
	var scoreAdjustment int
	var probRange [2]float64

	switch schemeType {
	case "冲刺":
		scoreAdjustment = 20             // 冲刺方案：比考生分数高20分的学校
		probRange = [2]float64{0.1, 0.3} // 录取概率10%-30%
	case "稳妥":
		scoreAdjustment = 0              // 稳妥方案：与考生分数相近的学校
		probRange = [2]float64{0.6, 0.8} // 录取概率60%-80%
	case "保底":
		scoreAdjustment = -30             // 保底方案：比考生分数低30分的学校
		probRange = [2]float64{0.9, 0.99} // 录取概率90%-99%
	}

	// 筛选符合条件的高校
	candidateUniversities := filterUniversities(req, scoreAdjustment)

	// 为每个候选高校计算推荐度并排序
	for i, uni := range candidateUniversities {
		if i >= count {
			break
		}

		// 选择合适的专业
		major := selectBestMajor(uni, req)

		// 计算录取概率
		admissionProb := calculateAdmissionProbability(req.Score, uni, probRange)

		// 计算分数和排名差距
		scoreDiff := req.Score - getUniversityMinScore(uni)
		rankDiff := req.Rank - getUniversityMinRank(uni)

		// 生成推荐理由
		reason := generateRecommendReason(uni, major, schemeType, admissionProb)

		// 确定风险等级
		riskLevel := determineRiskLevel(admissionProb)

		recommendation := RecommendedUniversity{
			University:      uni,
			Major:           major,
			AdmissionProb:   admissionProb,
			ScoreDifference: scoreDiff,
			RankDifference:  rankDiff,
			RecommendReason: reason,
			RiskLevel:       riskLevel,
		}

		recommendations = append(recommendations, recommendation)
	}

	// 生成风险警告和建议
	riskWarning := generateRiskWarning(schemeType, recommendations)
	suggestions := generateSuggestions(schemeType, req, recommendations)

	return RecommendationResult{
		SchemeType:   schemeType,
		Universities: recommendations,
		TotalCount:   len(recommendations),
		RiskWarning:  riskWarning,
		Suggestions:  suggestions,
	}
}

// 筛选符合条件的高校
func filterUniversities(req RecommendationRequest, scoreAdjustment int) []ExtendedUniversity {
	filtered := []ExtendedUniversity{}
	targetScore := req.Score + scoreAdjustment

	for _, uni := range extendedUniversities {
		// 检查省份偏好
		if req.PreferredArea != "" && req.PreferredArea != "不限" && uni.Province != req.PreferredArea {
			continue
		}

		// 检查院校类型偏好
		if len(req.UniversityType) > 0 {
			typeMatch := false
			for _, uType := range req.UniversityType {
				if uni.Level == uType || uni.Type == uType {
					typeMatch = true
					break
				}
			}
			if !typeMatch {
				continue
			}
		}

		// 检查分数范围（模拟历史录取分数）
		minScore := getUniversityMinScore(uni)
		if abs(targetScore-minScore) <= 50 { // 分数差距在50分以内
			filtered = append(filtered, uni)
		}
	}

	return filtered
}

// 辅助函数实现
func selectBestMajor(uni ExtendedUniversity, req RecommendationRequest) ExtendedMajor {
	// 根据专业偏好选择最合适的专业
	for _, major := range extendedMajors {
		if major.UniversityID == uni.ID {
			if req.PreferredMajor == "" || req.PreferredMajor == "不限" || major.Category == req.PreferredMajor {
				return major
			}
		}
	}

	// 如果没有找到匹配的专业，返回该校第一个专业
	for _, major := range extendedMajors {
		if major.UniversityID == uni.ID {
			return major
		}
	}

	// 如果还是没有找到，返回默认专业
	return ExtendedMajor{
		ID:           0,
		UniversityID: uni.ID,
		Code:         "000000",
		Name:         "通用专业",
		Category:     "综合",
		IsActive:     true,
		Duration:     4,
		Degree:       "学士",
		Description:  "通用专业描述",
	}
}

func calculateAdmissionProbability(score int, uni ExtendedUniversity, probRange [2]float64) float64 {
	// 基于分数和学校排名计算录取概率
	minScore := getUniversityMinScore(uni)
	scoreDiff := score - minScore

	// 根据分数差距调整概率
	var prob float64
	if scoreDiff >= 30 {
		prob = probRange[1] // 高概率
	} else if scoreDiff >= 0 {
		prob = (probRange[0] + probRange[1]) / 2 // 中等概率
	} else {
		prob = probRange[0] // 低概率
	}

	// 根据学校层次微调概率
	if uni.Level == "985" {
		prob *= 0.9 // 985学校录取难度更高
	} else if uni.Level == "211" {
		prob *= 0.95
	}

	return prob
}

func getUniversityMinScore(uni ExtendedUniversity) int {
	// 根据学校排名和层次估算最低录取分数
	baseScore := 500

	if uni.Level == "985" {
		baseScore = 620 + (40-uni.NationalRank)*2
	} else if uni.Level == "211" {
		baseScore = 580 + (100-uni.NationalRank)*1
	} else {
		baseScore = 520 + (200-uni.NationalRank)*1
	}

	return baseScore
}

func getUniversityMinRank(uni ExtendedUniversity) int {
	// 根据学校排名估算最低录取排名
	if uni.Level == "985" {
		return uni.NationalRank * 1000
	} else if uni.Level == "211" {
		return uni.NationalRank * 800
	} else {
		return uni.NationalRank * 500
	}
}

func generateRecommendReason(uni ExtendedUniversity, major ExtendedMajor, schemeType string, prob float64) string {
	reasons := []string{}

	// 基于学校特色
	if uni.Level == "985" {
		reasons = append(reasons, "985工程重点大学，学术声誉卓著")
	} else if uni.Level == "211" {
		reasons = append(reasons, "211工程重点大学，教学质量优秀")
	}

	// 基于专业特色
	if major.Category == "工学" {
		reasons = append(reasons, "工学专业就业前景广阔")
	} else if major.Category == "经济学" {
		reasons = append(reasons, "经济学专业社会需求量大")
	}

	// 基于录取概率
	if prob >= 0.8 {
		reasons = append(reasons, "录取概率较高，建议重点考虑")
	} else if prob >= 0.5 {
		reasons = append(reasons, "录取概率适中，可作为主要选择")
	} else {
		reasons = append(reasons, "录取概率较低，建议谨慎考虑")
	}

	// 基于方案类型
	switch schemeType {
	case "冲刺":
		reasons = append(reasons, "冲刺院校，有机会进入更好平台")
	case "稳妥":
		reasons = append(reasons, "稳妥选择，录取把握较大")
	case "保底":
		reasons = append(reasons, "保底院校，确保有学可上")
	}

	if len(reasons) > 0 {
		return strings.Join(reasons, "；")
	}
	return "综合评估推荐"
}

func determineRiskLevel(prob float64) string {
	if prob >= 0.8 {
		return "低风险"
	} else if prob >= 0.5 {
		return "中风险"
	} else {
		return "高风险"
	}
}

func generateRiskWarning(schemeType string, recommendations []RecommendedUniversity) string {
	switch schemeType {
	case "冲刺":
		return "冲刺方案录取概率较低，建议合理搭配稳妥和保底方案"
	case "稳妥":
		return "稳妥方案录取概率适中，建议关注专业选择和地域因素"
	case "保底":
		return "保底方案录取概率较高，建议优先考虑专业和学校发展前景"
	default:
		return "请根据个人情况合理选择志愿方案"
	}
}

func generateSuggestions(schemeType string, req RecommendationRequest, recommendations []RecommendedUniversity) []string {
	suggestions := []string{}

	// 通用建议
	suggestions = append(suggestions, "建议详细了解各高校的专业设置和培养方案")
	suggestions = append(suggestions, "关注高校的地理位置和就业情况")
	suggestions = append(suggestions, "考虑个人兴趣和职业规划")

	// 基于方案类型的建议
	switch schemeType {
	case "冲刺":
		suggestions = append(suggestions, "冲刺方案风险较高，建议做好心理准备")
		suggestions = append(suggestions, "可以考虑专业调剂以增加录取机会")
	case "稳妥":
		suggestions = append(suggestions, "稳妥方案是主要选择，建议重点关注")
		suggestions = append(suggestions, "可以适当考虑专业优先还是学校优先")
	case "保底":
		suggestions = append(suggestions, "保底方案确保录取，建议选择发展潜力大的学校")
		suggestions = append(suggestions, "关注学校的升学和就业数据")
	}

	return suggestions
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

